class Solution:
    def countMonobit(self, n):
        count = 0
        for x in range(n + 1):
            b = bin(x)[2:]
            if len(set(b)) == 1:
                count += 1
        return count

solutions.python:
class Solution:
    def countMonobit(self, n):
        count = 1
        m = 1
        val = 1
        while val <= n:
            count += 1
            m += 1
            val = (1 << m) - 1
        return count

